import * as fs from 'fs-extra';
import * as path from 'path';
import * as stream from 'stream';
import * as request from 'request';
import * as url from 'url';
import uuid = require('uuid');
import blobToBuffer = require('blob-to-buffer');

import {promisify} from './decorators';

import Log = require('jibo-log');
const log = new Log('Asset');


export type ErrCallback = (err)=>void;
export type DataCallback = (err?:any, data?:any)=>void;
export type BlobCallback = (err?:any, blob?:Blob)=>void;
export type FilenameCallback = (err?:any, filename?:string)=>void;
export type FilenameOrUrlCallback = (err?:any, filenameOrUrl?:string)=>void;


/** Asset storage object. Assets are binary files attached to a node.
 * Use `node.createAsset()` to create an asset object. Asset objects have
 * minimal meta information about the asset file: just subtype and
 * file extension. All other metadata should be stored in the node it
 * is attached to.
 *
 * @class Asset
 * @memberof jibo.kb
 * @param {string} [filenameOrUrl] Filename to asset on disk, or url
 * to asset via KB service.
 * @param {string} [subtype] Subtype name of asset. Defaults to `asset`.
 * @param {string} [ext] Optional filename extension.
 */
export default class Asset {
    public _id:string;
    public subtype:string;
    public ext:string;
    public rootDir:string;


    constructor(filenameOrURL?:string, subtype?:string, ext?:string) {
        if (!filenameOrURL) {
            this._id     = uuid.v4();
            this.subtype = subtype || 'asset';
            this.ext     = ext;
        } else {
            this.setSelfFromFilenameOrURL(filenameOrURL);
        }
    }


    /** Set root directory for this asset.
     *
     * @method jibo.kb.Asset#setRootDir
     * @param {string} rootDir The full directory name or base URL
     * that points to the storage area for this asset in its KB slice
     * (which must be the same as the node it is attached to).
     * @internal
     */
    public setRootDir(rootDir:string) {
        this.rootDir = rootDir;
    }


    /** The filename for this asset, without any directory
     * information. Format of the filename is:
     *
     * `{$_id}.{$subtype}.{$ext}`.
     *
     * If the asset doesn't have an extension, `{$ext}` (and its dot
     * seperator) will be absent.
     *
     * @method jibo.kb.Asset#filename
     * @returns {string} The filename.
     */
    public filename():string {
        // we should filter id, subtype, and ext for /,.,.. baddies FIXME
        let filename = `${this._id}.${this.subtype}`;
        if (this.ext) { filename += `.${this.ext}`; }  // ext is optional
        return filename;
    }


    /** Full path to the asset file on disk or a URL to fetch it
     * via the KB service.
     *
     * @method jibo.kb.Asset#fullFilenameOrURL
     * @returns {string} Full path filename or URL.
     */
    public fullFilenameOrURL():string {
        if (!this.rootDir) { throw new Error('asset rootDir not set'); }
        let filename:string;
        if (this.rootDir.startsWith('http://')) {
            filename = this._url();
        } else {
            filename = this.filename();
            filename = path.join(this.rootDir, 'assets', filename);
        }
        return filename;
    }


    /** Print useful console logs from asset objects.
     *
     * @method jibo.kb.Asset#toString
     * @returns {string} Full path filename or URL.
     */
    public toString():string { return this.fullFilenameOrURL(); }


    /** Write out the data for this asset file. Data can be provided
     * as a readable stream, buffer, or blob.
     *
     * @method jibo.kb.Asset#save
     * @param {Stream|Buffer|Blob} data Data to be saved in asset file.
     * @param {Function} [callback] Called when done. If callback is
     * omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     */
    public save(data:any, callback:FilenameOrUrlCallback);
    public save(data:any):Promise<string>;
    @promisify
    public save(data:any, callback?:FilenameOrUrlCallback):void|Promise<string> {
        if (this.rootDir.startsWith('http://')) {
            if ((data instanceof Buffer) || (data instanceof stream.Stream)) {
                this._saveViaWeb(data, callback);
            } else {
                blobToBuffer(data, (err, buffer) => {
                    log.iferr(err, 'blobToBuffer');
                    if (!err) {
                        this._saveViaWeb(buffer, callback);
                    } else {
                        callback(err);
                    }
                });
            }
        } else {
            if (data instanceof Buffer) {
                this._saveBuffer(data, callback);
            } else if (data instanceof stream.Stream) {
                this._saveStream(data, callback);
            } else {
                blobToBuffer(data, (err, buffer) => {
                    log.iferr(err, 'blobToBuffer');
                    if (!err) {
                        this._saveBuffer(buffer, callback);
                    } else {
                        callback(err);
                    }
                });
            }
        }
    }


    /** Set up an asset object by parsing an asset filename or
     * URL. Sets the `_id`, `subtype`, and `ext`. Set rootDir if full
     * path filename or URL.
     *
     * @method jibo.kb.Asset#setSelfFromFilenameOrURL
     * @param {string} filenameOrUrl Filename, full path filename, or URL.
     */
    public setSelfFromFilenameOrURL(filenameOrURL:string) {
        if (filenameOrURL.startsWith('http://')) {
            this._setSelfFromURL(filenameOrURL);
        } else {
            this._setSelfFromFilename(filenameOrURL);
        }
    }


    /** Load the binary file pointed to by this asset object.
     * Returns a buffer (via callback) with the contents (data) of the file.
     *
     * @method jibo.kb.Asset#load
     * @param {Function} [callback] Called with (err, data) when
     * done. If callback is omitted a promise that resolves to `data`
     * is returned instead.
     * @returns {Promise} A promise that resolves with the value of
     * `data` if the callback is omitted.
     */
    public load(callback:DataCallback);
    public load():Promise<any>;
    @promisify
    public load(callback?:DataCallback):void|Promise<any> {
        if (this.rootDir.startsWith('http://')) {
            this._loadBufferViaWeb(callback);
        } else {
            let filename = this.fullFilenameOrURL();
            fs.readFile(filename, (err, data) => {
                log.iferr(err, 'readFile on', filename);
                callback(err, data);
            });
        }
    }


    /** Create a stream of the binary file this asset object points to.
     * Return a stream (via callback) of the contents (data)
     * of the file.
     *
     * @method jibo.kb.Asset#loadStream
     * @returns {Stream} Stream of binary asset data.
     */
    public loadStream():stream.Stream {
        if (this.rootDir.startsWith('http://')) {
            return this._loadStreamViaWeb();
        } else {
            let filename = this.fullFilenameOrURL();
            return fs.createReadStream(filename);
        }
    }


    /** Load the binary file pointed to by this asset object.
     * Returns a blob (via callback) with the contents (data) of the file.
     *
     * @method jibo.kb.Asset#loadBlob
     * @param {Function} [callback] Called with (err, data) when
     * done. If callback is omitted a promise that resolves to `data`
     * is returned instead.
     * @returns {Promise} A promise that resolves with the value of
     * `data` if the callback is omitted.
     */
    public loadBlob(callback:BlobCallback);
    public loadBlob():Promise<Blob>;
    @promisify
    public loadBlob(callback?:BlobCallback):void|Promise<Blob> {
        // warning: this is untested and mainly guesswork
        this.load( (err, data) => {
            let blob:Blob;
            log.iferr(err, 'could not load asset file');
            if (!err) {
                blob = new Blob(data, {type: 'application/octet-binary'});
                // or maybe: blob = new window.Blob([new Uint8Array(data)]);
            }
            callback(err, blob);
        });
    }


    /** Remove the asset file from disk.
     *
     * @method jibo.kb.Asset#remove
     * @param {Function} [callback] Called when done. If callback is
     * omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     */
    public remove(callback:ErrCallback);
    public remove():Promise<any>;
    @promisify
    public remove(callback?:ErrCallback):void|Promise<any> {
        if (this.rootDir.startsWith('http://')) {
            this._removeViaWeb(callback);
        } else {
            let filename = this.fullFilenameOrURL();
            log.info('removing asset file', filename);
            fs.unlink(filename, (err) => {
                log.iferr(err, 'fs.unlink of', filename);
                if (!err) {
                    log.debug('asset file', filename, 'removed from disk');
                }
                callback(err);
            });
        }
    }


    /** Assemble the URL for this asset.
     *
     * @method jibo.kb.Asset#_url
     * @returns {string} URL
     * @private
     */
    private _url():string {
        if (!this.rootDir) { throw new Error('asset rootDir not set'); }
        let filename = this.filename();
        return `${this.rootDir}/asset/${filename}`;
    }


    /** Saves the asset data via the KB service web interface.
     *
     * @method jibo.kb.Asset#_saveViaWeb
     * @private
     */
    private _saveViaWeb(data:any, callback:FilenameOrUrlCallback) {
        let url = this._url();
        let opts = {
            body: data,
            headers: { 'Content-Type': 'application/octet-stream' }
        };
        request.post(url, opts, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.post', url);
            callback(err, url);
        });
    }


    /** Set up an asset by parsing a filename
     *
     * @method jibo.kb.Asset#_setSelfFromFilename
     * @param {string} filename Filename or full path filename
     * @private
     */
    private _setSelfFromFilename(filename:string) {
        // if filename starts with '/', also set rootDir
        if (path.isAbsolute(filename)) {
            this.rootDir = path.dirname( path.dirname(filename) );  // twice removes '/assets' off end
            filename = path.basename(filename);
        }
        let re = new RegExp(`^([^.]*)[.]([^.]*)([.]([^.]*))?$`);
        let vals = filename.match(re);
        if (!vals) { throw new Error('filename did not parse'); }
        this._id  = vals[1];
        this.subtype = vals[2] || '';
        this.ext     = vals[4] || '';
    }


    /** Set up an asset from a URL
     *
     * @method jibo.kb.Asset#_setSelfFromURL
     * @param {string} URL
     * @private
     */
    private _setSelfFromURL(httpurl:string) {
        let urlParts = url.parse(httpurl);
        let pathParts = urlParts.pathname.split('/');
        let rootPath = pathParts.slice(0, 3).join('/');
        this.rootDir = `http://${urlParts.hostname}:${urlParts.port}/${rootPath}`;
        let filename = pathParts[pathParts.length-1];
        this._setSelfFromFilename(filename);
    }


    /** Remove the asset file from disk via KB service.
     *
     * @method jibo.kb.Asset#_removeViaWeb
     * @param {Function} callback Called when done
     * @private
     */
    private _removeViaWeb(callback:ErrCallback) {
        let url = this._url();
        request.del(url, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.delete', url);
            callback(err);
        });
    }


    /** Save asset file from buffer.
     *
     * @method jibo.kb.Asset#_saveBuffer
     * @param {Buffer} buffer Data to be saved in asset file
     * @param {Function} callback Called when done
     * @private
     */
    private _saveBuffer(buffer:Buffer, callback:FilenameCallback) {
        if (!buffer) { callback(); return; }
        let filename = this.fullFilenameOrURL();
        fs.ensureDir(path.dirname(filename), (err) => {
            log.iferr(err, 'ensureDir');
            if (!err) {
                log.info('writing asset file', filename);
                fs.writeFile(filename, buffer, (err) => {
                    log.iferr(err, 'file write error', filename);
                    callback(err, filename);
                });
            } else {
                callback(err);
            }
        });
    }


    /** Save asset file from stream.
     *
     * @method jibo.kb.Asset#_saveStream
     * @param {Stream} stream Data to be saved in asset file
     * @param {Function} callback Called when done
     * @private
     */
    private _saveStream(stream:stream.Stream, callback:FilenameCallback) {
        if (!stream) { callback(); return; }
        let filename = this.fullFilenameOrURL();
        fs.ensureDir(path.dirname(filename), (err) => {
            log.iferr(err, 'ensureDir');
            if (!err) {
                log.info('writing asset file', filename);
                let writeStream = fs.createWriteStream(filename);
                stream.pipe(writeStream);
                writeStream.on('finish', () => {
                    callback(null, filename);
                });
                writeStream.on('error', (err) => {
                    log.error('file write error', filename, err);
                });
            } else {
                callback(err);
            }
        });
    }


    /** Loads the asset via the KB service.
     *
     * @method jibo.kb.Asset#_loadBufferViaWeb
     * @param {Function} callback Called with (err, data) when done
     * @private
     */
    private _loadBufferViaWeb(callback:DataCallback) {
        let url = this._url();
        let opts = {
            headers: { 'Content-Type': 'application/octet-stream' },
            // encoding: null to get a binary
            // see http://stackoverflow.com/questions/14855015/getting-binary-content-in-node-js-using-request
            encoding: null
        };
        request.get(url, opts, (err, res, body) => {
            err = this._checkStatusCode(err, res, body);
            log.iferr(err, 'request.get', url);
            callback(err, body);
        });
    }


    /** Loads a stream of the asset via the KB service.
     *
     * @method jibo.kb.Asset#_loadStreamViaWeb
     * @returns {Stream} Stream of asset
     * @private
     */
    private _loadStreamViaWeb():stream.Stream {
        let url = this._url();
        let opts = {
            headers: { 'Content-Type': 'application/octet-stream' },
            // encoding: null to get a binary
            // see http://stackoverflow.com/questions/14855015/getting-binary-content-in-node-js-using-request
            encoding: null
        };
        return request.get(url, opts);
    }


    /** Check http request result for null error object and 2xx result code and
     * generate an error object if not (or pass through non null error object).
     *
     * @method jibo.kb.Asset#_checkStatusCode
     * @param {Error} err Error object returned from request
     * @param {Object} res Http request result object
     * @param {string} [message] Message to add to error object
     * @returns {Error} Error object or null
     * @private
     */
    private _checkStatusCode(err:Error, res, message:string=null):Error {
        if (!err) {  // game over if we already have an err
            if (res.statusCode < 200 || res.statusCode > 299) {
                let description = 'HTTP Error Code '+res.statusCode;
                if (message) {
                    description += message;
                }
                err = new Error(description);
            }
        }
        return err;
    }
}
