import request = require('request');

import {promisify} from './decorators';
import UserNode from './UserNode';
import Model from './Model';
import Node from './Node';

import Log = require('jibo-log');
const log = new Log('LoopModel');

export type ErrCallback = (err)=>void;
export type UsersCallback = (err, users?:UserNode[])=>void;
export type UserCallback = (err:string, user?:UserNode)=>void;
export type UserNameCallback = (err:string, userName?:string)=>void;

export interface EnrollmentParams {
    memberId: string;
    loopId?: string;
    voice?: boolean;
    face?: boolean;
};

/**
 * Jibo KB Loop API
 * @namespace jibo.kb.loop
 */

/** LoopModel Class. The Loop Model subclass
 *
 * @class LoopModel
 * @extends jibo.kb.Model
 * @memberof jibo.kb.loop
 * @example
 * let model = jibo.kb.loop.createModel('/skillname');
 */
export default class LoopModel extends Model {

    /** Load status `accepted` loop members.  These are the current
     * loop members. If callback is omitted a promise is returned
     * instead.
     *
     * @method jibo.kb.loop.LoopModel#loadLoop
     * @param {Function} [callback] Called with (err, loop). If callback
     * is omitted a promise that resolves to `loop` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `loop` if the callback is omitted.
     */
    public loadLoop(callback:UsersCallback);
    public loadLoop():Promise<UserNode[]>;
    @promisify
    public loadLoop(callback?:UsersCallback):void|Promise<UserNode[]> {
        this.loadLoopAll( (err, loop) => {
            if (!err) {
                callback(null, this._onlyAccepted(loop));
            } else {
                callback(err);
            }
        });
    }


    /** Load status `invited` loop members.  These are loop the
     * members who have not yet accepted their invitation to join the
     * loop. If callback is omitted a promise is returned instead.
     *
     * @method jibo.kb.loop.LoopModel#loadLoopInvited
     * @param {Function} [callback] Called with (err, loop). If callback
     * is omitted a promise that resolves to `loop` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `loop` if the callback is omitted.
     */
    public loadLoopInvited(callback:UsersCallback);
    public loadLoopInvited():Promise<UserNode[]>;
    @promisify
    public loadLoopInvited(callback?:UsersCallback):void|Promise<UserNode[]> {
        this.loadLoopAll( (err, loop) => {
            if (!err) {
                callback(null, this._onlyInvited(loop));
            } else {
                callback(err);
            }
        });
    }


    /** Load `isActive` loop members.
     *
     * @method jibo.kb.loop.LoopModel#loadLoopActive
     * @param {Function} [callback] Called with (err, loop). If callback
     * is omitted a promise that resolves to `loop` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `loop` if the callback is omitted.
     */
    public loadLoopActive(callback:UsersCallback);
    public loadLoopActive():Promise<any>;
    @promisify
    public loadLoopActive(callback?:UsersCallback):void|Promise<any> {
        this.loadLoopAll( (err, loop) => {
            if (!err) {
                callback(null, this._onlyActive(loop));
            } else {
                callback(err);
            }
        });
    }


    /** Load all loop members, including where `status` is `deleted`.
     *
     * @method jibo.kb.loop.LoopModel#loadLoopAll
     * @param {Function} [callback] Called with (err, loop). If callback
     * is omitted a promise that resolves to `loop` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `loop` if the callback is omitted.
     */
    public loadLoopAll(callback:UsersCallback);
    public loadLoopAll():Promise<UserNode[]>;
    @promisify
    public loadLoopAll(callback?:UsersCallback):void|Promise<UserNode[]> {
        this.loadRoot(null, (err, rootNode) => {
            log.iferr(err, 'loadRoot');
            if (!err && rootNode) {
                let userIds = rootNode.getEdges('user');
                this.load(userIds, (err, nodes) => {
                    log.iferr(err, 'load');
                    callback(err, <UserNode[]>nodes);
                });
            } else {
                callback(err);
            }
        });
    }

    /** Retrieve loop member's node.
     *
     * @method jibo.kb.loop.LoopModel#getUserNodeById
     * @param {String} id The loop member's ID.
     * @param {Function} [callback] Called with (err, node). If callback
     * is omitted a promise that resolves to `node` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `node` if the callback is omitted.
     * @internal
     */
    public getUserNodeById(id:string, callback:UserCallback);
    public getUserNodeById(id:string):Promise<UserNode>;
    @promisify
    public getUserNodeById(id:string, callback?:UserCallback):void|Promise<UserNode> {
        this.loadLoop((err, loop:UserNode[]) => {
            if (err) {
                return callback(err);
            }

            // find the user node from specified id
            let user = loop.find((node) => {
                return node.id === id;
            });

            if(user) {
                callback(null, user);
            }
            else {
                callback('Could not find user node for loop id ' + id);
            }

        });

    }

    /** Retrieve loop member's written name.
     *
     * @method jibo.kb.loop.LoopModel#getWrittenNameById
     * @param {String} id The loop member's ID.
     * @param {Function} [callback] Called with (err, name). If
     * callback is omitted a promise that resolves to `name` is
     * returned instead.
     * @returns {Promise} A promise that resolves with the value of
     * `name` if the callback is omitted.
     */
    public getWrittenNameById(id:string, callback:UserNameCallback);
    public getWrittenNameById(id:string):Promise<string>;
    @promisify
    public getWrittenNameById(id:string, callback?:UserNameCallback):void|Promise<string> {
        this.getUserNodeById(id, (error, user) => {
            if (error) {
                return callback(error);
            }

            // use user's written name API
            callback(null, user.getWrittenName());
        });
    }

    /** Retrieve loop member's spoken name.
     *
     * @method jibo.kb.loop.LoopModel#getSpokenNameById
     * @param {String} id The loop member's ID.
     * @param {Function} [callback] Called with (err, name). If callback
     * is omitted a promise that resolves to `name` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `name` if the callback is omitted.
     */
    public getSpokenNameById(id:string, callback:UserNameCallback);
    public getSpokenNameById(id:string):Promise<string>;
    @promisify
    public getSpokenNameById(id:string, callback?:UserNameCallback):void|Promise<string> {
        this.getUserNodeById(id, (error, user) => {
            if (error) {
                return callback(error);
            }

            // use phonetic name if it exists
            callback(null, user.toString());
        });
    }


    /** Fetch status `accepted` loop members from the
     * cache. These are the current loop members.
     *
     * @method jibo.kb.loop.LoopModel#fetchLoop
     * @returns {jibo.kb.loop.UserNode[]} Array of loop members.
     */
    public fetchLoop():UserNode[] {
        return this._onlyAccepted( this.fetchLoopAll() );
    }


    /** Fetch status `invited` loop members from the
     * cache.  These are the loop members who have not yet accepted
     * their invitation to join the loop.
     *
     * @method jibo.kb.loop.LoopModel#fetchLoopInvited
     * @returns {jibo.kb.loop.UserNode[]} Array of invited loop members.
     */
    public fetchLoopInvited():UserNode[] {
        return this._onlyInvited( this.fetchLoopAll() );
    }


    /** Fetch `isActive` loop members from the cache.
     *
     * @method jibo.kb.loop.LoopModel#fetchLoopActive
     * @returns {jibo.kb.loop.UserNode[]} Array of active loop members.
     */
    public fetchLoopActive():UserNode[] {
        return this._onlyActive( this.fetchLoopAll() );
    }


    /** Fetch all loop members from the cache, including where status
     * is `deleted`.
     *
     * @method jibo.kb.loop.LoopModel#fetchLoopAll
     * @returns {jibo.kb.loop.UserNode[]} Array of all loop members.
     */
    public fetchLoopAll():UserNode[] {
        return <UserNode[]>this.fetch( this.fetchRoot().getEdges('user') );
    }


    /** Set the phonetic name of a loop member in the cloud.
     *
     * @method jibo.kb.loop.LoopModel#setPhoneticName
     * @param {string|jibo.kb.Node} idOrNode The loop member's
     * ID or Node.
     * @param {String} phoneticName The phonetic name value.
     * @param {Function} [callback] Called when done. If callback is
     * omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     * @internal
     */
    public setPhoneticName(idOrNode:string|Node, phoneticName:string, callback:ErrCallback);
    public setPhoneticName(idOrNode:string|Node, phoneticName:string):Promise<any>;
    @promisify
    public setPhoneticName(idOrNode:string|Node, phoneticName:string, callback?:ErrCallback):void|Promise<any> {
        let accountId:string = (typeof idOrNode === 'object') ? idOrNode._id : idOrNode;

        let url = `${this.httpUrl}/v1/loop/updatePhoneticName`;
        this.loadRoot( (err, root) => {
            log.iferr(err, 'loadRoot');
            let params = {
                loopId: root.data.id,
                memberId: accountId,
                phoneticName: phoneticName
            };
            request.post(url, {json: params}, (err, res, body) => {
                //err = this._checkStatusCode(err, res, body);  // FIXME temp. disabled to ease transition from old api to new api
                log.iferr(err, 'request.post', url);
                if (callback) {
                    callback(err);
                }
            });
        });
    }


    /** Set the face enrollment flag of a loop member in the cloud.
     *
     * @method jibo.kb.loop.LoopModel#setEnrollmentFace
     * @param {string|jibo.kb.Node} idOrNode The loop member's
     * ID or Node.
     * @param {boolean} face The face enrollment flag.
     * @param {Function} [callback] Called when done. If callback is
     * omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     * @internal
     */
    public setEnrollmentFace(idOrNode:string|Node, face:boolean, callback:ErrCallback);
    public setEnrollmentFace(idOrNode:string|Node, face:boolean):Promise<any>;
    @promisify
    public setEnrollmentFace(idOrNode:string|Node, face:boolean, callback?:ErrCallback):void|Promise<any> {
        let memberId:string = (typeof idOrNode === 'object') ? idOrNode._id : idOrNode;

        let params = {
            memberId: memberId,
            face: !!face
        };
        this.setEnrollment(params, callback);
    }


    /** Set the voice enrollment flag of a loop member in the cloud.
     *
     * @method jibo.kb.loop.LoopModel#setEnrollmentVoice
     * @param {string|jibo.kb.Node} idOrNode The loop member's
     * ID or Node.
     * @param {boolean} voice The voice enrollment flag.
     * @param {Function} [callback] Called when done. If callback is
     * omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     * @internal
     */
    public setEnrollmentVoice(idOrNode:string|Node, voice:boolean, callback:ErrCallback);
    public setEnrollmentVoice(idOrNode:string|Node, voice:boolean):Promise<any>;
    @promisify
    public setEnrollmentVoice(idOrNode:string|Node, voice:boolean, callback?:ErrCallback):void|Promise<any> {
        let memberId:string = (typeof idOrNode === 'object') ? idOrNode._id : idOrNode;

        let params = {
            memberId: memberId,
            voice: !!voice
        };
        this.setEnrollment(params, callback);
    }


    /** Set the enrollment flag(s) of a loop member in the cloud.
     *
     * @method jibo.kb.loop.LoopModel#setEnrollment
     * @param {Object} params Enrollment
     * parameters (memberId and face/voice flags)
     * @param {Function} [callback] Called when done. If callback is
     * omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     * @internal
     */
    public setEnrollment(params:EnrollmentParams, callback:ErrCallback);
    public setEnrollment(params:EnrollmentParams):Promise<any>;
    @promisify
    public setEnrollment(params:EnrollmentParams, callback?:ErrCallback):void|Promise<any> {
        let url = `${this.httpUrl}/v1/loop/enrollment`;
        this.loadRoot( (err, root) => {
            log.iferr(err, 'loadRoot');
            params.loopId = root.data.id;
            request.post(url, {json: params}, (err, res, body) => {
                err = this._checkStatusCode(err, res, body);
                log.iferr(err, 'request.post', url);
                if (callback) {
                    callback(err);
                }
            });
        });
    }


    /** Filter out loop members that have not accepted yet.
     *
     * @method jibo.kb.loop.LoopModel#_onlyAccepted
     * @param {jibo.kb.loop.UserNode[]} loop Loop nodes to filter.
     * @returns {jibo.kb.loop.UserNode[]} Loop nodes where `status` is 'accepted'.
     * @private
     */
    private _onlyAccepted(loop:UserNode[]):UserNode[] {
        return loop.filter( (user) => { return user.data.status === "accepted"; } );
    }


    /** Filter out loop members that don't have a pending invitation.
     *
     * @method jibo.kb.loop.LoopModel#_onlyInvited
     * @param {jibo.kb.loop.UserNode[]} loop Loop nodes to filter.
     * @returns {jibo.kb.loop.UserNode[]} Loop nodes where `status` is 'invited'.
     * @private
     */
    private _onlyInvited(loop:UserNode[]):UserNode[] {
        return loop.filter( (user) => { return user.data.status === "invited"; } );
    }


    /** Filter out loop members that are not `isActive`.
     *
     * @method jibo.kb.loop.LoopModel#_onlyActive
     * @param {jibo.kb.loop.UserNode[]} loop Loop nodes to filter.
     * @returns {jibo.kb.loop.UserNode[]} Loop nodes where `isActive` is true.
     * @private
     */
    private _onlyActive(loop:UserNode[]):UserNode[] {
        return loop.filter( (user) => { return user.data.isActive; } );
    }

    /** Check http request result for null error object and 2xx result code and
     * generate an error object if not (or pass through non null error object).
     *
     * @method jibo.kb.WebClient#_checkStatusCode
     * @param {Error} err Error object returned from request.
     * @param {Object} res Http request result object.
     * @param {string} [message] Message to add to error object.
     * @returns {Error} Error object or null.
     * @private
     */
    private _checkStatusCode(err:Error, res, message:string=null):Error {
        if (!err) {  // game over if we already have an err
            if (res.statusCode < 200 || res.statusCode > 299) {
                let description = 'HTTP Error Code '+res.statusCode;
                if (message) {
                    description += message;
                }
                err = new Error(description);
            }
        }
        return err;
    }
}
