import Node from './Node';

//defined here so that the type of UserNode.data.account is less confusing to look at in code
export type AccountData = {
    birthday:number,
    email:string,
    firstName:string,
    gender:'male'|'female'|'other',
    lastName:string
};
/**
 * Specific type of node for members of the loop. All nodes returned by LoopModel should be UserNodes.
 *
 * @class UserNode
 * @extends jibo.kb.Node
 * @memberof jibo.kb.loop
 */
export default class UserNode extends Node {
    public data: {
        account:AccountData,
        birthday:number,
        email:string,
        enrolled:{voice:boolean, face:boolean},
        facebookConnected:boolean,
        firstName:string,
        gender:'male'|'female'|'other',
        isActive:boolean,
        lastName:string,
        loopId:string,
        memberId:string,
        phoneticName:string,
        photoUrl:string,
        nickName:string,
        status:string,
        type:string
    };

    //provided to make things a little easier, also allow people to use UserNodes where they had
    // {id:'blahblah'}
    /**
     * UUID of the user.
     * @name jibo.kb.loop.UserNode#id
     * @type {String}
     */
    public get id():string {
        return this._id;
    }

    /**
     * First name of the user.
     * @name jibo.kb.loop.UserNode#firstName
     * @type {String}
     */
    public get firstName():string {
        return this.data.firstName;
    }

    /**
     * Last name of the user.
     * @name jibo.kb.loop.UserNode#lastName
     * @type {String}
     */
    public get lastName():string {
        return this.data.lastName;
    }

    /**
     * Nickname of the user.
     * @name jibo.kb.loop.UserNode#nickName
     * @type {String}
     */
    public get nickName():string {
        return this.data.nickName;
    }

    /**
     * Gender of the user.
     * @name jibo.kb.loop.UserNode#gender
     * @type {String}
     */
    public get gender() {
        return this.data.gender;
    }

    /**
     * If this loop member is actually Jibo.
     * @name jibo.kb.loop.UserNode#isJibo
     * @type {Boolean}
     */
    public get isJibo():boolean {
        return !this.data.firstName;
    }

    /**
     * The loop member's preferred written name. This will be the nickname or first name
     * of the loop member.
     * @method jibo.kb.loop.UserNode#getWrittenName
     * @return {String} The loop member's preferred written name.
     */
    public getWrittenName():string {
        return this.data.nickName || this.data.firstName || 'Jibo';
    }

    /**
     * The loop member's preferred spoken name. This will be the `phoneticName`, nickname, or first name
     * of the loop member.
     * @method jibo.kb.loop.UserNode#toString
     * @return {String} The loop member's preferred spoken name.
     */
    public toString():string {
        return this.data.phoneticName || this.getWrittenName();
    }

    /**
     * Calculate the initials of the loop member.
     * @method jibo.kb.loop.UserNode#getInitials
     * @return {String} The loop member's initials.
     */
    public getInitials():string {
        if (this.isJibo) {
            return 'J';
        }
        //shouldn't be needed, but just to prevent most possible errors
        if (!this.data.firstName || !this.data.lastName) {
            return '';
        }
        return this.data.firstName.charAt(0).toUpperCase() +
                this.data.lastName.charAt(0).toUpperCase();
    }
}
