import fs = require('fs-extra');
import path = require('path');

import Database from './Database';
import Node from './Node';


import Log = require('jibo-log');
const log = new Log('KnowledgeDatabase');


export type ErrCallback = (err)=>void;
export type NodeCallback = (err, node?:Node)=>void;
export type CountCallback = (err, count?:number)=>void;
export type NodeConstructor = new (...args:any[])=>Node;

const reservedNames = ['nodes', 'assets'];

const RunMode = {
    /** Running in the simulator. */
    SIMULATOR: "SIMULATOR",
    /** Running in remote mode. */
    REMOTELY: "REMOTELY",
    /** Running on the robot. */
    ON_ROBOT: "ON_ROBOT",
    /** Running in dev mode, no SSM */
    UNIT_TESTS: "UNIT_TESTS"
};


/** KnowledgeDatabase Class. Represents a single KB instance or
 * "slice" (e.g. `/jibo.loop` or `/snap`) with all it's nodes and
 * assets. Uses a Database class instance (i.e. Node Embedded Database [NeDB]) to load/store
 * the nodes.
 *
 * Not usually used directly. Instead A Model assembles one or more
 * KnowledgeDatabase objects into a model and interaction with the
 * databases is done through the Model.
 *
 * This version of the class is intended for the server side of the KB
 * service which maniplates the on disk files using the Database class
 * (which uses itself NeDB).  WebClient is a subclass of this class
 * and is what is used client side.
 *
 * @class KnowledgeDatabase
 * @memberof jibo.kb
 * @param {string} kbName Name of this KB slice.
 * @internal
 */
class KnowledgeDatabase {
    public dbDirectory:string;
    public dbFilename:string;
    public database:Database;


    /** Return the root directory for all KnowledgeDatabases.
     *
     * @method jibo.kb.KnowledgeDatabase.getRootDirectory
     * @static
     * @returns {string} Full path to the root directory of all
     * KnowledgeDatabases.
     * @internal
     */
    public static getRootDirectory():string {
        if (this._onRobot()) {
            return '/opt/jibo/Knowledge';
        } else {
            return path.join(process.env.HOME || process.env.USERPROFILE, '.jibo', 'kb');
        }
    }


    /** Calculate the full path to the directory of a KB slice.
     *
     * @method jibo.kb.KnowledgeDatabase.getKbDirectory
     * @static
     * @param {string} kbName Name of KB slice.
     * @returns {string} Full path to the KB slice directory.
     * @internal
     */
    public static getKbDirectory(kbName:string):string {
        KnowledgeDatabase._validateKbName(kbName);  // throws error on failure
        let rootDirectory = KnowledgeDatabase.getRootDirectory();
        // should probably filter kbName to not have anything nasty
        // like '/' or '.' or '..' etc. FIXME
        return path.join(rootDirectory, kbName);
    }


    /** Calculate the full path to the NeDB file of a KB slice.
     *
     * @method jibo.kb.KnowledgeDatabase.getKbFilename
     * @static
     * @param {string} kbName Name of KB slice.
     * @returns {string} Full path to the NeDB `nodes` file.
     * @internal
     */
    public static getKbFilename(kbName:string):string {
        KnowledgeDatabase._validateKbName(kbName);  // throws error on failure
        const dbDirectory = KnowledgeDatabase.getKbDirectory(kbName);
        return path.join(dbDirectory, 'nodes');
    }


    /** Validate the kbName. We are starting out very conservatively.
     * Throws an error if the name doesn't pass.
     *
     * @method jibo.kb.KnowledgeDatabase.validateKbName
     * @static
     * @param {string} kbName Name of KB slice.
     * @private
     * @internal
     */
    private static _validateKbName(kbName) {
        // 200 leaves room for kb root directory
        // typical max path lengths:
        //   260 in windows (or maybe even 248)
        //   250 in os x < 10.6, 1016 in os x >= 10.6
        //   4096 in linux ext*
        if (kbName.length > 200) {
            throw new Error('kb name is too long');
        }
        // check for only valid characters (a-z,0-9,slash,_,-)
        // means no unicode or international characters
        // don't want any '.' or '..' filename security busting foolishness
        // restricting to lowercase because os x hfs default is case insensitive
        // we use UUIDs with dashes in them, so we should allow then in kb names too
        if (/[^a-z0-9\/_-]/.test(kbName)) {
            throw new Error('illegal character in kb name');
        }
        // can't end with a slash
        if (kbName.endsWith('/')) {
            throw new Error('kb name ends with a slash');
        }

        let parts = kbName.split('/');

        // don't let them go too deep, for now
        // 10 deep is arbitrary
        if (parts.length > 10) {
            throw new Error('kb name has too many sub directories');
        }
        parts.forEach( (part, n) => {
            // can't be empty, don't allow '//'.
            if (part.length === 0 && n !== 0) {  // but the first one can be empty (starts with /)
                throw new Error('kb name component is empty');
            }
            // don't let a single directory name be too long
            // 75 is arbitrary. v4 UUIDs are 36 (32+4 dashes), so bigger than that
            if (part.length > 75) {
                throw new Error('kb name component is too long');
            }
            // must start with an alphanumeric.
            // also reserves names starting with '_' for potential internal use
            if (/^[^a-z0-9]/.test(part)) {
                throw new Error('kb names must start with an alphanumeric character');
            }
            // can't be 'nodes' or 'assets' as we use those to actually store the data
            if (reservedNames.indexOf(part) >= 0) {
                throw new Error('kb name is reserved word');
            }
        });
    }


    /** Determine if we are running on the robot or in the simulator.
     *
     * @method jibo.kb.KnowledgeDatabase#_onRobot
     * @returns {boolean} `true` if on robot. `false` if in simulator.
     * @static
     * @private
     * @internal
     */
    private static _onRobot():boolean {
        // TODO should be done centrally again someday
        let runMode = process.env.runMode || process.env.RUNMODE;
        if (!runMode && process.platform === 'linux' && process.arch === 'arm') {
            // only default to ON_ROBOT under Linux
            // this lets all the existing unit tests run unmodified
            runMode = RunMode.ON_ROBOT;
        }
        return (runMode === RunMode.ON_ROBOT);
    }


    constructor(public kbName:string) {
        KnowledgeDatabase._validateKbName(kbName);  // throws error if kbName is invalid
        this.dbDirectory = KnowledgeDatabase.getKbDirectory(this.kbName);
        this.dbFilename = KnowledgeDatabase.getKbFilename(this.kbName);
    }


    /** Initalize this KnowledgeDatabase slice - Attach to or create
     * the underlying file on disk (via the Database class).
     *
     * @method jibo.kb.KnowledgeDatabase#init
     * @param {Function} callback Called with (err) when done.
     */
    public init(callback:ErrCallback) {
        this._setupDirectory( (err) => {
            log.iferr(err, 'KnowledgeDatabase#_setupDirectory');
            if (!err) {
                this.database = new Database(this.dbFilename);
                this.database.init( (err, nodeCount) => {
                    log.iferr(err, 'Database#init');

                    // set up and save initial root node if KB is empty
                    if (!err) {
                        if (nodeCount === 0) {
                            log.info('creating root node for', this.kbName);
                            let NodeClass = Node.findNodeClass('root', this.kbName);
                            let rootNode = new NodeClass('root');
                            this.adoptNodeAsOurOwn(rootNode);
                            rootNode.save( (err) => {
                                log.iferr(err, 'error creating initial root node for', this.kbName);
                                callback(err);
                            });
                        } else {
                            callback(err);
                        }
                    } else {
                        callback(err);
                    }
                });
            }
        });
    }


    /** Load a node of a given ID.
     *
     * @method jibo.kb.KnowledgeDatabase#load
     * @param {string} id ID of node to load via the KB service.
     * @param {Function} callback Called with (err, node).
     * @internal
     */
    public load(id:string, callback:NodeCallback) {
        this.database.load(id, (err, data) => {
            if (!err) {
                let node:Node = null;  // return `null` if not found
                if (data) {
                    node = this.createNodeFromObject(data);
                }
                callback(null, node);
            } else {
                callback(err);
            }
        });
    }


    /** Load the root node of this KB slice.
     *
     * @method jibo.kb.KnowledgeDatabase#loadRoot
     * @param {Function} callback Called with (err, rootNode).
     * @internal
     */
    public loadRoot(callback:NodeCallback) {
        this.database.loadNodeOfType('root', (err, data) => {
            log.iferr(err, 'Database#loadNodeOfType');
            let node:Node;
            if (!err && data) {
                node = this.createNodeFromObject(data);
            }
            callback(err, node);
        });
    }


    /** Save a given node into this KB slice.
     *
     * @method jibo.kb.KnowledgeDatabase#save
     * @param {jibo.kb.Node} node The node to be saved.
     * @param {Function} callback Called with (err) when done.
     * @internal
     */
    public save(node:Node, callback:ErrCallback) {
        node.setUpdated();
        this.database.save(node, (err) => {
            if (callback) {
                callback(err);
            }
        });
    }


    /** Remove a node from this KB slice.
     *
     * @method jibo.kb.KnowledgeDatabase#remove
     * @param {string|jibo.kb.Node} idOrNode Id string or Node object to be
     * removed.
     * @param {Function} callback Called with (err) when done.
     * @internal
     */
    public remove(idOrNode:string|Node, callback:CountCallback) {
        let id:string = this.toId(idOrNode);
        this.database.remove(id, callback);
    }


    /** Given an object from a Database (or from a web request),
     * convert into a full Node object. Uses the Node Class registry
     * on the `kb` object to find the proper Node subclass, if any.
     * Also binds the Node to this KnowledgeDatabase.
     *
     * @method jibo.kb.KnowledgeDatabase#createNodeFromObject
     * @param {Object} object Object to be converted to a Node
     * object. Must have an `_id` property, should have a `type`
     * property (defaults to `node`).
     * @returns {jibo.kb.Node} The Node object, or a Node subclass object.
     * @internal
     */
    public createNodeFromObject(object:{type:string}):Node {
        let nodeType = object.type || 'node';
        let NodeClass = Node.findNodeClass(nodeType, this.kbName);
        let node = new NodeClass(null, null, object);
        this.adoptNodeAsOurOwn(node);
        return node;
    }


    /** Create a new Node object. Uses the Node Class registry on the
     * `kb` object to find a proper Node subclass, if any. Also binds
     * the Node to this KnowledgeDatabase.
     *
     * @method jibo.kb.KnowledgeDatabase#createNode
     * @param {string|Class} nodeTypeOrClass A string stating the node
     * type, or a Node Class constructor.
     * @param {Object} [data] Inital node.data.
     * @returns {jibo.kb.Node} The new Node or Node subclass object.
     * @internal
     */
    public createNode(nodeTypeOrClass:string|NodeConstructor, data?:any):Node {
        let NodeClass:NodeConstructor;
        let nodeType:string;
        if (typeof nodeTypeOrClass === 'function') {  // we were given a class constructor (hopefully)
            NodeClass = nodeTypeOrClass;
        } else {
            nodeType = nodeTypeOrClass;
            NodeClass = Node.findNodeClass(nodeType, this.kbName);
            if (nodeType === 'root') {  // loophole if they pass in a kb.Node.Root constructor
                throw new Error('can not create additional root nodes');
            }
        }
        let node:Node;
        if (nodeType && NodeClass === Node) {
            node = new NodeClass(nodeType, data);
        } else {
            node = new NodeClass(data);
        }
        this.adoptNodeAsOurOwn(node);
        return node;
    }


    /** Bind a given node to this KB slice.
     *
     * @method jibo.kb.KnowledgeDatabase#adoptNodeAsOurOwn
     * @param {jibo.kb.Node} node Node to be adopted.
     * @internal
     */
    public adoptNodeAsOurOwn(node:Node) {
        node.setKb(this);
    }


    /** Return the directory for this KnowledgeDatabase.
     *
     * @method jibo.kb.KnowledgeDatabase#getDirectory
     * @returns {string} Full path to the directory of this
     * KnowledgeDatabase.
     * @internal
     */
    public getDirectory():string {
        return this.dbDirectory;
    }


    /** Convert an idOrNode parameter to an id if it's a node.
     *
     * @method jibo.kb.KnowledgeDatabase#toId
     * @param {string|jibo.kb.Node} Id string, or node with an ._id property.
     * @returns {string} ID
     * @private
     * @internal
     */
    protected toId(idOrNode:string|Node):string {
        if (typeof idOrNode === 'object') {
            idOrNode = (<Node>idOrNode)._id;
        }
        return <string>idOrNode;
    }


    /** Create directory for this KnowledgeDatabase if it doesn't
     * exist.
     *
     * @method jibo.kb.KnowledgeDatabase#_setupDirectory
     * @param {Function} callback Called with (err) when done.
     * @private
     * @internal
     */
    private _setupDirectory(callback:ErrCallback) {
        fs.ensureDir(this.dbDirectory, callback);
    }
}


export default KnowledgeDatabase;
